package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.InputStream;
import java.net.URL;
import java.nio.charset.Charset;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class CSVParserTest {

    private URL mockUrl;
    private InputStream mockInputStream;
    private Charset charset;
    private CSVFormat format;

    @BeforeEach
    void setUp() throws Exception {
        mockUrl = mock(URL.class);
        mockInputStream = mock(InputStream.class);
        charset = Charset.forName("UTF-8");
        format = mock(CSVFormat.class);
    }

    @Test
    void parse_NullUrl_ThrowsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse((URL) null, charset, format);
        });
        assertEquals("url", ex.getMessage());
    }

    @Test
    void parse_NullCharset_UsesUtf8Charset() throws IOException, Exception {
        when(mockUrl.openStream()).thenReturn(mockInputStream);

        // Use reflection to temporarily replace Charset.forName("UTF-8") result
        // with our charset instance by mocking Charset.forName via a helper class.
        // Since Mockito.mockStatic is not available, we use reflection to override Charset.forName method.
        // But Charset.forName is final static native, so we cannot override directly.
        // Instead, we can spy on Charset class and replace the charset variable via reflection in CSVParser class.
        // However, the CSVParser.parse method calls Charset.forName inside the method, so we cannot intercept it easily.
        // As a workaround, we can test the behavior by passing null charset and verifying the URL openStream is called.

        try (CSVParser parser = CSVParser.parse(mockUrl, null, format)) {
            assertNotNull(parser);
        }

        verify(mockUrl).openStream();
    }

    @Test
    void parse_NullFormat_ThrowsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(mockUrl, charset, null);
        });
        assertEquals("format", ex.getMessage());
    }

    @Test
    void parse_ValidArguments_ReturnsCSVParser() throws IOException {
        when(mockUrl.openStream()).thenReturn(mockInputStream);

        try (CSVParser parser = CSVParser.parse(mockUrl, charset, format)) {
            assertNotNull(parser);
        }

        verify(mockUrl).openStream();
    }
}
